// ─── Transcrição: vem direto do node Gemini, não do agente ───
const transcription = $('Transcreve com Google Gemini').first().json?.content?.parts?.[0]?.text || '';

// ─── Resumo: vem do Agente Sumarizador ───
const summary = $input.first().json.output.summary_text || '';

// ─── Monta documento: transcrição em cima, resumo embaixo ───
const TRANSCRIPTION_HEADER = '🎙 TRANSCRIÇÃO COMPLETA\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';
const SEPARATOR = '\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n📋 RESUMO\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';

const fullText = TRANSCRIPTION_HEADER + transcription + SEPARATOR + summary;

// ─── Normaliza quebras de linha ───
let text = fullText.replace(/\r\n/g, '\n');

// ─── Parser de estilos (bold, italic, bullets) ───
let plainText = '';
let styles = [];
let bullets = [];
let cursor = 1;

const lines = text.split('\n');

for (let line of lines) {
  if (!line.trim()) {
    plainText += '\n';
    cursor++;
    continue;
  }

  let isBullet = false;
  if (line.trim().startsWith('✦') || line.trim().startsWith('✓') || line.trim().startsWith('-')) {
    isBullet = true;
    line = line.trim().substring(1).trim();
  }

  const regex = /(\*\*([^*]+)\*\*|\*([^*]+)\*|([^*]+))/g;
  let match;
  while ((match = regex.exec(line)) !== null) {
    let raw = match[0];
    let clean = match[2] || match[3] || match[4] || '';
    const start = cursor;
    const end = cursor + clean.length;

    plainText += clean;

    if (raw.startsWith('**')) {
      styles.push({
        range: { startIndex: start, endIndex: end },
        textStyle: { bold: true },
        fields: 'bold'
      });
    } else if (raw.startsWith('*')) {
      styles.push({
        range: { startIndex: start, endIndex: end },
        textStyle: { italic: true },
        fields: 'italic'
      });
    }

    cursor = end;
  }

  plainText += '\n';
  cursor++;

  if (isBullet) {
    bullets.push({
      range: {
        startIndex: cursor - line.length - 1,
        endIndex: cursor
      },
      bulletPreset: 'BULLET_DISC_CIRCLE_SQUARE'
    });
  }
}

// ─── Monta requests para BatchUpdate API ───
let requests = [];

requests.push({
  insertText: {
    endOfSegmentLocation: {},
    text: plainText
  }
});

for (let s of styles) {
  requests.push({
    updateTextStyle: {
      range: s.range,
      textStyle: s.textStyle,
      fields: s.fields
    }
  });
}

for (let b of bullets) {
  requests.push({
    createParagraphBullets: b
  });
}

return [{ json: { requests } }];

